/* Embedded fonts for the PDF export: Hanken Grotesk (400/700) + Geist Mono (400). */
(function(root){
  var F={hN:"",hB:"",gM:""};
  root.registerPdfFonts=function(pdf){
    pdf.addFileToVFS("Hanken-Regular.ttf",F.hN); pdf.addFont("Hanken-Regular.ttf","Hanken","normal");
    pdf.addFileToVFS("Hanken-Bold.ttf",F.hB);    pdf.addFont("Hanken-Bold.ttf","Hanken","bold");
    pdf.addFileToVFS("GeistMono-Regular.ttf",F.gM); pdf.addFont("GeistMono-Regular.ttf","GeistMono","normal");
  };
})(typeof window!=="undefined"?window:globalThis);
